"""
mkt-context layer — 1 Peter chapters 1–4 (fills all missing verses; ch1 v1 and ch2 v13 already present)
Output: data/commentary/mkt-context/1peter.json
Run: python3 scripts/zc-context-1peter-1-4-full.py

Setting: 1 Peter is written from Rome ('Babylon,' 5:13) c. 62-64 CE, during Nero's reign,
to exiles/diaspora Christians in five provinces of Asia Minor (Pontus, Galatia, Cappadocia,
Asia, Bithynia). The audience faces social hostility and discrimination — not yet formal
Roman state persecution, but local social exclusion as religious non-conformists.

Key interpretation decisions:
- 'Exiles' and 'foreigners' (parepidēmoi, paroikoi): read as both literal social status
  (resident aliens without full citizen rights) and theological metaphor.
- 3:19 'spirits in prison': most likely the fallen Watchers of Gen 6 / 1 Enoch tradition,
  not deceased humans generally — an early Jewish apocalyptic interpretation.
- 'Babylon' (5:13): Rome — standard Jewish and early Christian cryptonym.
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {
  "1": {
    "2": "<p>'Chosen according to the foreknowledge of God the Father, through the sanctifying work of the Spirit, to be obedient to Jesus Christ and sprinkled with his blood' — the Trinitarian structure (Father's foreknowledge → Spirit's sanctification → Christ's blood) mirrors early Christian baptismal formulas; Peter applies all three persons to the election of dispersed Gentile Christians. The 'sprinkling of blood' evokes both the Passover blood on the doorposts (Exod 12:22-23) and the Sinai covenant-ratification ceremony (Exod 24:3-8: Moses sprinkled blood on the people and said, 'This is the blood of the covenant').</p>",
    "3": "<p>'Praise be to the God and Father of our Lord Jesus Christ! In his great mercy he has given us new birth into a living hope through the resurrection of Jesus Christ from the dead' — the berakah-style blessing (praise be to God) is the standard Jewish prayer formula (<em>barukh atah</em>) adapted into a Christian doxology centered on the resurrection. The 'new birth' (<em>anagennēsas</em>) language situates the Christian experience within both Jewish proselyte baptism (conversion to Judaism involved ritual immersion as a 'new birth' in rabbinic thought) and the broader Greco-Roman mystery-religion context where initiation rites were described as rebirth.</p>",
    "4": "<p>'An inheritance that can never perish, spoil, or fade, kept in heaven for you' — the triple negative compound (<em>aphtharton, amianton, amaranton</em>) is rhetorical and emphatic: imperishable, undefiled, and unfading. The language contrasts the inheritance of the scattered diaspora communities (who have no ancestral land, no national heritage, no civic inheritance in their host cities) with the eschatological inheritance preserved for them. The diaspora's landlessness is reframed: their true inheritance exceeds any territory in the Roman empire.</p>",
    "5": "<p>'Shielded by God's power through faith until the coming of the salvation that is ready to be revealed in the last time' — the military metaphor of being 'shielded' (<em>phrouroumenous</em>, garrisoned, guarded by a military guard) is vivid for an Asia Minor audience where Roman garrison troops were a feature of provincial life. The salvation that is 'ready to be revealed' (<em>apokalyphthēnai</em>) is the apocalyptic disclosure language of Jewish and early Christian eschatology — the definitive intervention of God that the present suffering is the prelude to.</p>",
    "6": "<p>'For a little while you may have had to suffer grief in all kinds of trials' — the 'little while' (<em>oligon arti</em>) is the temporal frame of eschatological expectation: the suffering is real but temporally bounded by the coming revelation (v. 5). The 'all kinds of trials' (<em>poikilois peirasmois</em>) encompass the range of social exclusion that diaspora Christians experienced: loss of social networks, business partnerships severed, family estrangement, accusations of atheism (for refusing to participate in civic cult), charges of misanthropy.</p>",
    "7": "<p>'The proven genuineness of your faith — of greater worth than gold, which perishes even though refined by fire' — the metallurgical testing metaphor (faith refined as gold is refined in fire) was a standard Stoic and Jewish wisdom topos for suffering that purifies character; cf. Wis 3:6 (God tested them and found them worthy; like gold in a furnace he tested them). The comparison 'worth more than gold' is striking given that gold was the standard of maximum value in the ancient economy; the trials are revalued as producing something more valuable than the most precious commodity.</p>",
    "8": "<p>'Though you have not seen him, you love him; and even though you do not see him now, you believe in him and are filled with an inexpressible and glorious joy' — the situation of the audience: they are second-generation (or later) Christians who did not witness the earthly ministry of Jesus. Peter (an eyewitness) addresses those who love and believe without having seen — the very faith-posture that Jesus himself called blessed (John 20:29: blessed are those who have not seen and yet have believed). The 'inexpressible and glorious joy' (<em>chara aneklalētō kai dedoxasmenē</em>) is eschatological joy — the foretaste of the final glory.</p>",
    "9": "<p>'For you are receiving the end result of your faith, the salvation of your souls' — <em>telos</em> (end, goal, outcome) of faith is <em>sōtērian psychōn</em> (salvation of souls). In Hellenistic usage <em>psychē</em> (soul) often means the whole person rather than a disembodied spiritual essence; 'salvation of souls' is salvation of the whole self. The present tense 'you are receiving' (<em>komizomenoi</em>) frames salvation as both present possession and eschatological completion — the same double-aspect that characterizes much of 1 Peter's theology.</p>",
    "10": "<p>'Concerning this salvation, the prophets, who spoke of the grace that was to come to you, searched intently and with the greatest care' — Peter's hermeneutic: the OT prophets were not simply communicating to their own generations but were speaking proleptically about the grace that would come to Gentile communities in Peter's own day. This is a standard early Christian interpretation that reads OT prophecy as forward-pointing to the messianic age; Qumran pesher exegesis similarly read the prophets as speaking primarily about the Teacher of Righteousness and his community.</p>",
    "11": "<p>'Trying to find out the time and circumstances to which the Spirit of Christ in them was pointing when he predicted the sufferings of the Messiah and the glories that would follow' — the 'Spirit of Christ' (<em>to en autois pneuma Christou</em>) in the OT prophets is Peter's way of saying that the same Spirit who indwells Christian believers also spoke through Israel's prophets — a pneumatological continuity between old and new covenant. The twofold pattern — sufferings (<em>pathēmata</em>) then glories (<em>doxas</em>) — is the hermeneutical key: not just the Christ of glory but the Christ of suffering was the prophets' subject.</p>",
    "12": "<p>'It was revealed to them that they were not serving themselves but you, when they spoke of the things that have now been told you by those who have preached the gospel to you by the Holy Spirit sent from heaven. Even angels long to look into these things' — the angels who 'long to look' (<em>epithumousin parakupsai</em>) into the gospel mystery are depicted as stretching to peer into realities that surpass their own comprehensive knowledge. Early Jewish tradition (e.g., 1 Enoch 9:1-11; Jubilees) developed rich angelology; Peter's remark places the gospel above even angelic wisdom — a higher dignity than the Torah that was 'ordained through angels' (Gal 3:19; Acts 7:53).</p>",
    "13": "<p>'With minds that are alert and fully sober, set your hope on the grace to be brought to you when Jesus Christ is revealed' — the imperative 'gird up the loins of your mind' (<em>anazōsamenoi tas osphyas tēs dianoias</em>) is a metaphor from the Passover preparation (Exod 12:11: eat it with your loins girded, your sandals on your feet) applied to mental readiness. The community is to be as alert as the Israelites on the night of Exodus — ready for departure, poised for the final revelation. The eschatological frame: they live between the first coming (v. 3-12) and the revelation of Jesus Christ at his return.</p>",
    "14": "<p>'As obedient children, do not conform to the evil desires you had when you lived in ignorance' — the 'former ignorance' (<em>en tē agnoiai</em>) frames pre-conversion Gentile life as ignorance of the true God — a standard Jewish and Pauline characterization (Acts 17:30: the times of ignorance God overlooked; Eph 4:18: darkened understanding, excluded from the life of God because of the ignorance that is in them). Peter addresses a predominantly Gentile community whose moral formation was shaped by Greco-Roman polytheistic culture and its associated practices.</p>",
    "15": "<p>'Just as he who called you is holy, so be holy in all you do' — the holiness imperative grounds ethics in divine character: be what God is. This is the distinctively covenantal logic of OT ethics (Lev 19:2; 20:7, 26: be holy, for I the LORD your God am holy) applied to a diaspora community that lacks a land, a temple, and a national cultic system. The holiness Peter calls for is character-holiness — ethical distinctiveness — rather than cultic-ritual separation, though the two are not entirely separate in Second Temple Jewish thought.</p>",
    "16": "<p>'For it is written: 'Be holy, because I am holy'' — Peter quotes Lev 11:44-45 (also 19:2; 20:7) — the Levitical holiness code. That Peter reaches to Leviticus for his ethics is significant: he applies the purity standards of the Torah not as ceremonial requirements (circumcision, food laws, temple sacrifice) but as the underlying moral logic — be what God is. The Holiness Code of Leviticus was understood in Second Temple Judaism to describe the character of the covenant community as a whole; Peter extends this to the new-covenant community across ethnic and geographic boundaries.</p>",
    "17": "<p>'Since you call on a Father who judges each person's work impartially, live out your time as foreigners here in reverent fear' — the 'time as foreigners' (<em>paroikias</em>) is both a social reality and a theological posture. <em>Paroikos</em> was the technical Greek term for a resident alien — one who lived in a city without full civic rights: no right to own land, no political voice, no participation in the civic cult. The diaspora communities Peter addresses were literally <em>paroikoi</em>; Peter transforms this vulnerability into a theological identity: their true citizenship is elsewhere (Phil 3:20), and the one they call 'Father' is also impartial Judge.</p>",
    "18": "<p>'It was not with perishable things such as silver or gold that you were redeemed from the empty way of life handed down to you from your ancestors' — the redemption language (<em>elytrōthēte</em>) draws on both the Exodus tradition (God 'redeemed' Israel from Egypt with a mighty hand) and the Greco-Roman practice of manumission: enslaved persons could be purchased from their owners. The 'empty way of life handed down from ancestors' is the <em>patroparadotos</em> — the ancestral tradition, the inherited pattern of Gentile religious and moral practice. Silver and gold were the standard manumission price; Peter's point is that something far more costly has been paid.</p>",
    "19": "<p>'But with the precious blood of Christ, a lamb without blemish or defect' — the Passover-lamb imagery: Exod 12:5 required a lamb 'without defect' (<em>tamim</em>, LXX: <em>amōmon</em>). The cultic-purity requirement for Passover sacrifice becomes the metaphor for Christ's sinlessness as the condition for his atoning death. Isa 53:7 (he was led like a lamb to the slaughter) fuses with the Passover image in early Christian atonement theology. The 'precious' (<em>timiō</em>) blood stands in deliberate contrast to the 'perishable' (<em>phthartois</em>) silver and gold of v. 18 — inestimable value versus transient economic value.</p>",
    "20": "<p>'He was chosen before the creation of the world, but was revealed in these last times for your sake' — the pre-temporal election of Christ and his historical revelation are the two poles of Christological time. The 'last times' (<em>ep' eschatou tōn chronōn</em>) — the terminus of the ages — is the standard early Christian claim that the Christ-event inaugurated the final chapter of history. The same language appears in Heb 1:2 (in these last days he has spoken to us by his Son) and 1 Cor 10:11 (on whom the culmination of the ages has come). Peter's recipients are living in the last act of the cosmic drama.</p>",
    "21": "<p>'Through him you believe in God, who raised him from the dead and glorified him, and so your faith and hope are in God' — the resurrection and glorification of Christ are the foundation of the community's faith and hope. The resurrection-verification pattern (God raised him, therefore he is trustworthy) was the core of early Christian apologetic preaching (Acts 2:24-36; 17:31). The Gentile communities Peter addresses have no ancestral relationship with the God of Israel; their entry into faith is through Christ, who mediates the relationship with the God who raised him.</p>",
    "22": "<p>'Now that you have purified yourselves by obeying the truth so that you have sincere love for each other, love one another deeply, from the heart' — the purification 'by obeying the truth' is the purification of conversion: the reception of the gospel and the moral transformation it produces. The love-command that follows is the concrete expression of that purification: sincere (<em>anypokriton</em>, unhypocritical, without pretense) love and deep (<em>ektenōs</em>, stretched-out, strained, intense) love. The community's internal love is the social correlate of their shared redemption.</p>",
    "23": "<p>'You have been born again, not of perishable seed, but of imperishable, through the living and enduring word of God' — the 'seed' (<em>spora</em>) metaphor for the word of God draws on the parable of the sower (Mark 4:3-20) and on Stoic natural philosophy, in which the <em>logos spermatikos</em> (generative reason/word) was the principle of creation and growth. Peter's 'imperishable seed' contrasts with the perishable biological seed of natural generation: the new birth is of a different ontological order than natural birth. The 'living and enduring word of God' is the preached gospel-word that has the life of God in it.</p>",
    "24": "<p>'All people are like grass, and all their glory is like the flowers of the field; the grass withers and the flowers fall' — Peter quotes Isa 40:6-8 (Peter applies this to the Gentile communities' former way of life). The Isaiah passage was originally addressed to exilic Judah as consolation: despite the apparent power of Babylon, all flesh is transient; God's word stands. Peter applies the Isaiah consolation to his own scattered, socially precarious communities: the worldly structures that seem permanent (Roman imperial culture, the ancestral traditions of v. 18) are as temporary as grass.</p>",
    "25": "<p>'But the word of the Lord endures forever. And this is the word that was preached to you' — Peter completes the Isaiah quotation and then makes the exegetical move explicit: the 'word of the Lord that endures forever' of Isa 40:8 is identified with the gospel that the Petrine missionaries preached to these communities. Early Christian hermeneutic: the eschatological 'word' that Isaiah promised as standing permanently is the Christological proclamation. The preached gospel has the permanence and power of the eschatological word of God."
  },
  "2": {
    "1": "<p>'Therefore, rid yourselves of all malice and all deceit, hypocrisy, envy, and slander of every kind' — the 'therefore' (<em>oun</em>) connects the ethical imperative to the new birth through the living word (1:23-25). The vice list (malice, deceit, hypocrisy, envy, slander) describes the social pathologies of competitive Greco-Roman urban culture: the zero-sum world of honor and shame in which advancement required putting others down. Peter's communities, formed by the gospel-word, are called to a different social practice. The 'putting away' (<em>apothemenoi</em>) is a clothing metaphor — stripping off the old character garments.</p>",
    "2": "<p>'Like newborn babies, crave pure spiritual milk, so that by it you may grow up in your salvation' — the nursing metaphor for instruction was widespread in Hellenistic educational culture: Philo, Epictetus, and others used the milk-to-solid-food progression for intellectual development. Peter adapts it for the new birth context (1:23): those just born again need the nourishment appropriate to their new life. The 'pure spiritual milk' (<em>to logikon adolon gala</em>) — literally 'rational/word milk without guile' — may echo the Stoic <em>logos</em> concept while pointing to the word of the gospel.</p>",
    "3": "<p>'Now that you have tasted that the Lord is good' — a direct citation of Ps 34:8 LXX (<em>geusasthe kai idete hoti chrēstos ho kyrios</em>: taste and see that the Lord is good/gracious). The wordplay on <em>chrēstos</em> (good, gracious) and <em>Christos</em> (Christ, the Anointed) — homophone in Greek — made Ps 34:8 an especially apt text for early Christians: the goodness tasted is the goodness of Christ. The community's conversion experience is described as a 'tasting' — direct sensory encounter with the character of the Lord.</p>",
    "4": "<p>'As you come to him, the living Stone — rejected by humans but chosen by God and precious to him' — the 'living stone' (<em>lithon zōnta</em>) conflates the stone imagery from the OT stone-passages (Isa 28:16; Ps 118:22; Isa 8:14) with the resurrection: the stone that was rejected became the living stone. In Jewish tradition, the 'stone' that the builders rejected (Ps 118:22) was variously interpreted as Abraham, David, or the Messiah. The 'coming to' him (<em>proserchomenoi</em>) is the approach to the sanctuary — pilgrimage and worship language — applied to the community's ongoing relationship with the risen Lord.</p>",
    "5": "<p>'You also, like living stones, are being built into a spiritual house to be a holy priesthood, offering spiritual sacrifices acceptable to God through Jesus Christ' — the 'spiritual house' (<em>oikos pneumatikos</em>) and 'holy priesthood' (<em>hierateuma hagion</em>) democratize the Levitical and temple institutions. The <em>naos</em> (inner sanctuary) was accessible only to priests; the outer courts to laypeople. Peter's community is being built as the sanctuary itself, with every member serving as priest. The 'spiritual sacrifices' (<em>pneumatikas thysias</em>) are the community's worship — prayer, praise, moral life — offered through the mediating role of Christ.</p>",
    "6": "<p>'See, I lay a stone in Zion, a chosen and precious cornerstone, and the one who trusts in him will never be put to shame' — Peter quotes Isa 28:16 LXX, a text that in its original context addressed the Assyrian crisis: God's foundation-stone in Zion (perhaps the Davidic king) was more reliable than any foreign alliance. The LXX adds 'the one who trusts' (<em>ho pisteuōn</em>) — missing from the MT — making explicit the faith-element that Peter foregrounds. The stone in Zion becomes in Peter's exegesis the crucified and risen Christ who is laid as the community's foundation.</p>",
    "7": "<p>'Now to you who believe, this stone is precious. But to those who do not believe, 'The stone the builders rejected has become the cornerstone'' — Peter quotes Ps 118:22, a pilgrimage psalm sung at festival processions entering Jerusalem. Its 'rejected stone' was read in early Christian tradition as the crucifixion and resurrection: Jesus rejected by the temple establishment became the cornerstone (Mark 12:10-11; Acts 4:11). The contrast between believers ('precious to you') and non-believers ('a stone they stumble over') mirrors the double effect of the gospel in Paul (1 Cor 1:18: the word of the cross is folly to those perishing, but power to those being saved).</p>",
    "8": "<p>'A stone that causes people to stumble and a rock that makes them fall. They stumble because they disobey the message' — Peter adds Isa 8:14 (the LORD will become 'a stone that causes people to stumble and a rock that makes them fall for both houses of Israel'). In Isaiah 8, the stone of stumbling was the LORD himself, whose word of judgment the unfaithful rejected. The application to Christ who is both stumbling block and cornerstone maintains the identification of Jesus with the LORD of Isaiah — the same divine Person who was both the sanctuary and the scandal in Isaiah's day.</p>",
    "9": "<p>'But you are a chosen people, a royal priesthood, a holy nation, God's special possession, that you may declare the praises of him who called you out of darkness into his wonderful light' — the fourfold identity-declaration applies Exod 19:6 (kingdom of priests, holy nation) and Isa 43:20-21 (my chosen people, the people I formed for myself that they may proclaim my praise) to Gentile Christians. The community that has no ethnic heritage in Israel, no ancestral claim on the land, and no civic standing in the Roman empire is given the highest possible covenantal identity: the identity that was Israel's at Sinai.</p>",
    "10": "<p>'Once you were not a people, but now you are the people of God; once you had not received mercy, but now you have received mercy' — Peter cites Hos 1:6, 9 (Lo-Ammi: not my people; Lo-Ruhamah: not loved/not received mercy) and Hos 2:23 (I will call them 'my people' who are not my people). Hosea addressed the northern kingdom of Israel that had broken covenant with God; Peter applies the restoration-language to Gentile Christians who stand in the position of 'not a people' before their conversion. The mercy that restores 'not my people' to 'my people' is realized in the gospel.</p>",
    "11": "<p>'Dear friends, I urge you, as foreigners and exiles, to abstain from sinful desires, which wage war against your soul' — the <em>paroikous kai parepidēmous</em> (resident aliens and temporary visitors) returns to the social-status terminology of 1:1, 17. A <em>paroikos</em> was a free person who resided in a city without citizenship — paying taxes, subject to local law, but without civic rights or political voice. A <em>parepidēmos</em> was an even more temporary visitor. Peter's ethical argument: their precarious social status, rather than being a disadvantage, is a clarifying context for Christian ethics — the soul's warfare against sinful desire is more visible when you do not belong to the city.</p>",
    "12": "<p>'Live such good lives among the pagans that, though they accuse you of doing wrong, they may see your good deeds and glorify God on the day he visits us' — the 'day of visitation' (<em>en hēmera episkopēs</em>) is the eschatological coming of God, an OT image (Isa 10:3; Jer 6:15; Wis 3:7) in which God's coming brings both judgment and vindication. The strategy of visible good conduct in the face of false accusations is the community's public apologetic: not argument but life. The accusation of wrongdoing was a real feature of Roman-era hostility to Christians — Tacitus and Pliny both reference accusations of 'hatred of the human race.'</p>",
    "14": "<p>'Or to governors, who are sent by him to punish those who do wrong and to commend those who do right' — the provincial governors (<em>hēgemones</em>) were the emperor's representatives exercising judicial and administrative power in the provinces where Peter's communities lived (Pliny the Younger served as governor of Bithynia-Pontus c. 111-113 CE, decades after this letter; but his correspondence with Trajan about Christians shows the pattern Peter describes). The submission to governors is grounded in their God-ordained function of punishing wrongdoing and commending good — a function that Christian good conduct can engage positively.</p>",
    "15": "<p>'For it is God's will that by doing good you should silence the ignorant talk of foolish people' — the 'silencing' (<em>phimoun</em>, to muzzle) of ignorant accusations through good conduct is a public-apologetic strategy. The accusations Peter's communities face — atheism (refusing to honor the gods), misanthropy (social withdrawal from civic religious events), possibly even cannibalism and sexual immorality (misunderstandings of the Lord's Supper and 'love feasts') — are countered not primarily by reasoned defense but by visible conduct that contradicts the accusations.</p>",
    "16": "<p>'Live as free people, but do not use your freedom as a cover-up for evil; live as God's slaves' — the paradox of free-slaves (<em>eleutheroi... douloi theou</em>) captures the Christian freedom-within-obligation structure. In the Greco-Roman world, freedom (<em>eleutheria</em>) and slavery (<em>douleia</em>) were absolute opposites in social terms; the only exception was the philosopher's claim that the truly free person is the one who has conquered their passions, while the apparently free person enslaved to passion is truly a slave. Peter adapts this: genuine freedom is the freedom of those who are God's slaves — not subject to human compulsion while fully submitted to the divine will.</p>",
    "17": "<p>'Show proper respect to everyone, love the family of believers, fear God, honor the emperor' — the four-part summary moves from universal respect (panta timēsate, honor everyone) to the particular love of the brotherhood to the fear of God to the honor of the emperor. The placement of the emperor after 'fear God' is deliberate: the emperor is to be honored (<em>timēsate</em>) but God alone is to be feared (<em>phobeisthe</em>) — a subtle distinction that relativizes imperial authority within the larger framework of divine sovereignty.</p>",
    "18": "<p>'Slaves, in reverent fear of God submit yourselves to your masters, not only to those who are good and considerate, but also to those who are harsh' — the household code for enslaved persons (<em>oiketai</em>, house-slaves, specifically) was a feature of Hellenistic ethical teaching. Peter's code differs from its Greco-Roman parallels in grounding submission not in social order or master-benefit but in 'reverent fear of God' (<em>en phobo theou</em>) — the enslaved person's conduct is an act of worship, not social compliance. The asymmetric command (submit even to harsh masters) prepares for the Christ-suffering pattern that follows in vv. 21-25.</p>",
    "19": "<p>'For it is commendable if someone bears up under the pain of unjust suffering because they are conscious of God' — the key phrase is 'conscious of God' (<em>dia syneidesin theou</em>) — awareness of God's reality and claim. Stoic philosophy commended the bearing of unjust suffering as evidence of virtue and inner freedom; Peter transforms this: the grounding is not self-mastery but God-consciousness. The person who suffers unjustly while remaining 'conscious of God' — aware that the divine eye sees and the divine Judge is coming — is commended not for stoic endurance but for theocentric faithfulness.</p>",
    "20": "<p>'But if you suffer for doing good and you endure it, this is commendable before God' — Peter intensifies the argument: not only is God-conscious endurance of unjust suffering praiseworthy, it is specifically praiseworthy in God's estimation. The 'commendation before God' (<em>charis para theō</em>) is what the Hellenistic system called <em>charis</em> — the patron's favorable response to a client's good conduct. Peter reframes the honor-shame economy entirely: the judgment that matters is not the master's, not the city's, not the emperor's, but God's alone. The enslaved person who endures unjust suffering has God as the patron whose honor counts.</p>",
    "21": "<p>'To this you were called, because Christ suffered for you, leaving you an example, that you should follow in his steps' — the calling of enslaved persons to suffer unjustly is grounded in Christ's own suffering 'for you' (<em>hyper hymōn</em>) — substitutionary in nature, yet also exemplary. The word 'example' (<em>hypogrammon</em>) was a writing-practice term: the tracing-copy that students followed line-by-line to learn penmanship; Christ's suffering is the pattern to trace, not merely to admire from a distance. The 'following in his steps' (<em>epakolouthēsēte tois ichnesin autou</em>) is discipleship language: the same footprints that Christ left, believers are called to walk in.</p>",
    "22": "<p>'He committed no sin, and no deceit was found in his mouth' — Peter quotes Isa 53:9 almost verbatim. The 'Servant' of Isaiah 53 who 'had done no violence, and there was no deceit in his mouth' is identified with Jesus Christ, whose sinless death was the qualification for his atoning role. That Peter cites Isa 53 in the context of an instruction to enslaved persons is significant: the Servant who suffered unjustly at the hands of oppressive power is precisely the enslaved person's solidarity figure — the one who experienced the worst of what power can do to the powerless.</p>",
    "23": "<p>'When they hurled their insults at him, he did not retaliate; when he suffered, he made no threats. Instead, he entrusted himself to him who judges justly' — the non-retaliation is not passivity but the active surrender of the right to vindication to the one who will judge rightly. The 'entrusting' (<em>paredidou de tō krinonti dikaiōs</em>) is the handing-over of one's cause to the divine judge — the posture of Ps 31:5 (into your hands I commit my spirit) and of Jesus's own cry from the cross (Luke 23:46). For enslaved persons in the first-century context, this is not a counsel of permanent submission to injustice but a posture of eschatological confidence in the one whose judgment will ultimately prevail.</p>",
    "24": "<p>'He himself bore our sins in his body on the cross, so that we might die to sins and live for righteousness; by his wounds you have been healed' — Peter continues the Isa 53 catena: Isa 53:4-5 (surely he took up our infirmities... he was pierced for our transgressions... by his wounds we are healed) and 53:12 (he bore the sin of many). The 'cross' is literally 'the wood' (<em>xylou</em>, the tree) — Acts 5:30; 10:39 use the same term for the cross, which also evokes Deut 21:22-23 (anyone hung on a tree is under God's curse) — the curse-bearing dimension of Christ's death that Paul develops in Gal 3:13.</p>",
    "25": "<p>'For you were like sheep going astray, but now you have returned to the Shepherd and Overseer of your souls' — the shepherd-sheep imagery from Isa 53:6 (all we like sheep have gone astray; each has turned to his own way) is paired with the 'Shepherd and Overseer' (<em>ton poimena kai episkopon</em>) titles for Christ. <em>Episkopos</em> (overseer, bishop) was a management term in Greco-Roman administration (overseers of building projects, financial overseers); in the LXX it translates the Hebrew <em>paqid</em> (appointed officer). Peter applies the double title to Christ as the supreme Shepherd-Overseer under whom the community's human elders (5:1-4) exercise delegated authority."
  },
  "3": {
    "1": "<p>'Wives, in the same way submit yourselves to your own husbands so that, if any of them do not believe the word, they may be won over without words by the behavior of their wives' — the 'in the same way' (<em>homoiōs</em>) connects the wives' submission to the Christ-pattern of 2:21-25 and the slaves' submission of 2:18-20; the household code throughout is grounded in the Christ-example. The specific scenario — wives of non-believing husbands — was a common pastoral situation: the Pauline letters also address it (1 Cor 7:12-16). The argument is missionary-pragmatic: conduct speaks louder than words to a husband who has rejected the verbal proclamation.</p>",
    "2": "<p>'When they see the purity and reverence of your lives' — the 'purity' (<em>hagnēn</em>) is chastity and marital faithfulness; the 'reverence' (<em>phobō</em>) is the fear of God that governs the wife's conduct. The observation that conduct is 'seen' — that character is visible — presupposes the intimate social context of the household, where the wife's daily behavior is directly observed by her husband. The strategy of silent witness was not unique to Peter: Stoic moral philosophers also argued that the virtuous person's life is itself a philosophical demonstration.</p>",
    "3": "<p>'Your beauty should not come from outward adornment, such as elaborate hairstyles and the wearing of gold jewelry and fine clothes' — the critique of ostentatious jewelry and hairstyles was a standard topos in Greco-Roman moral philosophy (Plutarch, Musonius Rufus, Seneca all warn against excessive female adornment as evidence of vanity and moral weakness) and in Hellenistic Jewish literature (Philo). The specific items — braided hair, gold jewelry, fine clothing — are the markers of Roman aristocratic female display; Peter's critique aligns Christian women's conduct with the counter-cultural critique of luxury that both Jewish and Stoic moralists shared.</p>",
    "4": "<p>'Rather, it should be that of your inner self, the unfading beauty of a gentle and quiet spirit, which is of great worth in God's sight' — the 'inner self' (<em>ho kryptos tēs kardias anthrōpos</em>, the hidden person of the heart) mirrors Paul's 'inner person' (<em>ho esō anthrōpos</em>, Rom 7:22; 2 Cor 4:16; Eph 3:16). The 'gentle and quiet spirit' (<em>pneumatos praeōs kai hēsychiou</em>) is the character quality that the Beatitudes associate with the kingdom (Matt 5:5: blessed are the meek). The assessment 'of great worth in God's sight' (<em>enōpion tou theou polyteles</em>) redirects the honor-economy: divine valuation of inner character over human valuation of external display.</p>",
    "5": "<p>'For this is the way the holy women of the past who put their hope in God used to adorn themselves. They submitted themselves to their own husbands' — the 'holy women of the past' (<em>hai hagiai gynaikes hai ... kosmousai heautas</em>) are the matriarchs — Sarah, Rebekah, Rachel, Leah — who are commended in Jewish tradition as models of virtue. The matriarchs are the female counterparts to the patriarchs Abraham, Isaac, and Jacob; citing them grounds Peter's instruction in the long covenantal tradition of Israel's founding families.</p>",
    "6": "<p>'Like Sarah, who obeyed Abraham and called him her lord. You are her daughters if you do what is right and do not give way to fear' — the citation of Sarah calling Abraham 'lord' (<em>kyrios</em>) refers to Gen 18:12 LXX (Sarah's inner thought that Abraham is 'my lord'). The 'daughters of Sarah' (<em>tekna Saras</em>) are those who inherit her posture — just as Paul's 'children of Abraham' (Gal 3:7) are those who share Abraham's faith. The prohibition 'do not give way to fear' is the pastoral assurance: the submission Peter calls for is not coerced by terror but chosen in freedom and hope.</p>",
    "7": "<p>'Husbands, in the same way be considerate as you live with your wives, and treat them with respect as the weaker partner and as heirs together of the gracious gift of life' — the 'weaker partner' (<em>asthenesteri skeuei</em>, the weaker vessel) is a social-physical assessment in the context of Greco-Roman medical anthropology, not a judgment of moral or spiritual inferiority. The theological counterweight: 'heirs together of the gracious gift of life' (<em>synklēronomois charitos zōēs</em>) — in the eschatological inheritance, husband and wife are co-heirs with equal standing. The eschatological equality relativizes the hierarchical household code without abolishing its structure in the present age.</p>",
    "8": "<p>'Finally, all of you, be like-minded, be sympathetic, love one another, be compassionate and humble' — the five virtues of the community summary: <em>homophrones</em> (like-minded, sharing one mind), <em>sympatheis</em> (sympathetic, suffering with), <em>philadelphoi</em> (brother-loving), <em>eusplanchnoi</em> (compassionate, rich in inner feeling), <em>tapeinophrones</em> (humble-minded). These five are the character marks that the gospel produces in a diaspora community that must maintain cohesion under social pressure. The 'humble-minded' closes the list in contrast to the <em>alazoneia</em> (arrogant boasting) of Greco-Roman competitive culture.</p>",
    "9": "<p>'Do not repay evil with evil or insult with insult. On the contrary, repay with blessing, because to this you were called so that you may inherit a blessing' — the non-retaliation ethic mirrors the Christ-pattern of 2:23 and the Beatitudes (Matt 5:38-42: do not resist an evildoer; 5:11-12: blessed are you when people insult you). The calling to 'inherit a blessing' by blessing is the eschatological logic: the covenant blessing (Gen 12:2-3: I will bless you and you will be a blessing) is inherited by those who embody the blessing-over-curse pattern rather than retaliating within the honor-shame competition.</p>",
    "10": "<p>'Whoever would love life and see good days must keep their tongue from evil and their lips from deceitful speech' — Peter begins a long quotation from Ps 34:12-16, which runs through v. 12. Psalm 34 (an acrostic of David's deliverance from Abimelech, probably Achish of Gath, 1 Sam 21:10-15) is a wisdom psalm commending the fear of the LORD as the path to life and blessing. Peter uses the Psalm as the scriptural warrant for his community ethics of speech and peacemaking under social pressure.</p>",
    "11": "<p>'They must turn from evil and do good; they must seek peace and pursue it' — continuing the Ps 34:14 citation. The peace-seeking imperative (<em>zētēsatō eirēnēn kai diōxatō autēn</em>) is intensified by the verb 'pursue' (<em>diōkō</em>, to chase, to hunt) — peace is not passive but actively hunted. The irony that a community being hunted by social hostility is called to actively hunt peace is embedded in Peter's appropriation of Ps 34: the same Psalm that describes the LORD's protection of the righteous begins with the exhortation to flee from evil and pursue peace.</p>",
    "12": "<p>'For the eyes of the Lord are on the righteous and his ears are attentive to their prayer, but the face of the Lord is against those who do evil' — Ps 34:15-16 provides the theological foundation for the non-retaliation ethic: the LORD himself attends to the righteous and opposes evildoers. The community does not need to defend itself because the LORD's eyes and ears are already turned toward them, and the LORD's face (the most threatening expression of divine power) is already turned against their persecutors. The eschatological vindication is not the community's to achieve — it belongs to the Judge.</p>",
    "13": "<p>'Who is going to harm you if you are eager to do good?' — the rhetorical question assumes that the normal Roman judicial system will not target genuinely good citizens. Roman legal culture valued civic virtue and good order; a community that is visibly contributing to social goods rather than threatening them has practical legal protection. The argument is not naively optimistic (Peter knows his communities face hostility) but strategic: the first line of defense against false accusation is genuine virtue that makes the accusation implausible.</p>",
    "14": "<p>'But even if you should suffer for what is right, you are blessed. 'Do not fear what they fear; do not be frightened'' — the beatitude ('you are blessed,' <em>makarioi</em>) echoes Matt 5:10-12 (blessed are those who are persecuted because of righteousness). The quotation is from Isa 8:12-13 LXX, where Isaiah instructs his disciples not to fear the conspiracy that Ahaz fears (the Syro-Ephraimite coalition), but to fear the LORD alone. Peter applies the Isaianic call to fearlessness in the face of political threat to his communities' situation under Roman social pressure.</p>",
    "15": "<p>'But in your hearts revere Christ as Lord. Always be prepared to give an answer to everyone who asks you to give the reason for the hope that you have' — the 'apologetics' instruction uses the technical legal term <em>apologia</em> (defense, formal answer to a charge) — the same word Paul uses in Phil 1:7 and 2 Tim 4:16 for his legal defense before Roman courts. The community is to be ready to give a formal verbal account of their hope; the context suggests formal interrogation by Roman authorities rather than mere casual conversation. The setting is the kind of investigation that Pliny the Younger conducted with Christians in Bithynia (10.96).</p>",
    "16": "<p>'Keeping a clear conscience, so that those who speak maliciously against your good behavior in Christ may be ashamed of their slander' — the 'clear conscience' (<em>syneidesin echousin agathēn</em>) is a legal-forensic concept: the conscience that has no hidden guilt, so that a formal examination produces vindication rather than shame. The 'shame' of the accusers when their false charges cannot be sustained is the reversal of the honor-shame dynamics: those who slandered the community discover that the community's conduct disproves their accusations, and the shame returns to the accusers.</p>",
    "17": "<p>'For it is better, if it is God's will, to suffer for doing good than for doing evil' — the comparative 'it is better' (<em>kreitton</em>) applies the conventional Greek moral calculus of better-worse to a non-conventional conclusion. Greek wisdom (Aristotle, Socrates) agreed that it is better to suffer injustice than to do it; Peter takes this further — it is better to suffer unjustly (specifically as a Christian doing good) than to suffer justly (as an evildoer who deserves punishment). The grounding is theological: God's will (<em>to thelēma tou theou</em>) governs the community's suffering — it is not random.</p>",
    "18": "<p>'For Christ also suffered once for sins, the righteous for the unrighteous, to bring you to God. He was put to death in the body but made alive in the Spirit' — the 'once for sins' (<em>hapax peri hamartiōn</em>) echoes the language of Hebrews (7:27; 9:12, 26, 28; 10:10) for the once-for-all definitive nature of Christ's atoning death. The 'righteous for the unrighteous' (<em>dikaios hyper adikōn</em>) is the substitutionary formula. The death-in-body / alive-in-spirit contrast frames the passage into the difficult vv. 19-20: the spiritual realm in which Christ operated 'after being made alive' is the domain of the proclamation to the imprisoned spirits.</p>",
    "19": "<p>'After being made alive, he went and made proclamation to the imprisoned spirits' — the most debated verse in 1 Peter. The 'imprisoned spirits' (<em>pneumasin en phylakē</em>) are most likely the Watchers — the fallen divine beings of Gen 6:1-4 who, in the 1 Enoch tradition (chapters 6-16), were imprisoned in Sheol awaiting judgment. Peter draws on this tradition (2 Pet 2:4-5 and Jude 6 also reference the imprisoned angels) to describe Christ's victory-proclamation to the forces that had corrupted pre-flood humanity. The proclamation is not evangelism but a herald's announcement of Christ's triumph over cosmic powers.</p>",
    "20": "<p>'To those who were disobedient long ago when God waited patiently in the days of Noah while the ark was being built' — the connection to Noah identifies the imprisoned spirits as those associated with the pre-flood era. God's patient waiting (<em>apexedecheto... makrothymia</em>) during Noah's ark-building is the model for the patience with which God waits for human response in Peter's own day (2 Pet 3:9: he is patient with you, not wanting anyone to perish). The 'eight persons' (Noah and his family) who were saved through water provide the typological connection to baptism in v. 21.</p>",
    "21": "<p>'And this water symbolizes baptism that now saves you also — not the removal of dirt from the body but the pledge of a clear conscience toward God. It saves you by the resurrection of Jesus Christ' — the Noah-ark-water becomes the type (<em>antitypon</em>) of baptism: as eight were saved through water while the old world was destroyed, so believers are saved through baptismal water that marks the boundary between old and new creation. The clarification 'not the removal of dirt from the body' distinguishes Christian baptism from the ritual washings (<em>ablutions</em>) of Second Temple Judaism and Greco-Roman mystery religions; the efficacy is not the water itself but the resurrection of Christ and the conscience-pledge that accompanies it.</p>",
    "22": "<p>'Who has gone into heaven and is at God's right hand — with angels, authorities and powers in submission to him' — the ascension and enthronement formula: Christ at the right hand of God (Ps 110:1 LXX: sit at my right hand until I make your enemies a footstool) is the controlling image of early Christian eschatology. The 'angels, authorities, and powers in submission to him' (<em>angelōn kai exousiōn kai dynameōn hypotagerntōn autō</em>) echoes the cosmic powers of Eph 1:21 and Col 2:15. The same Christ who proclaimed victory to the imprisoned spirits (v. 19) is now enthroned above all cosmic powers — the entire angelic hierarchy is subject to him."
  },
  "4": {
    "1": "<p>'Therefore, since Christ suffered in his body, arm yourselves also with the same attitude, because whoever suffers in the body is done with sin' — the military metaphor of 'arming' (<em>hoplisasthe</em>) applied to the mind/attitude mirrors Paul's 'put on the full armor of God' (Eph 6:11-17). The phrase 'done with sin' (<em>pepautai hamartias</em>) has been variously interpreted: most likely it means that suffering functions as a moral purification — the person who commits to the Christ-suffering pattern has made a decisive break with the sin-serving lifestyle of their pre-conversion past (cf. v. 3's description of that past).</p>",
    "2": "<p>'As a result, they do not live the rest of their earthly lives for evil human desires, but rather for the will of God' — the contrast between 'evil human desires' (<em>epithumiais anthrōpōn</em>) and 'the will of God' (<em>thelēmati theou</em>) is the fundamental orientation-choice that conversion requires. The 'rest of their earthly time' (<em>ton epiloipon en sarki chronon</em>) frames the remainder of mortal life as a finite but critical period — the eschatological urgency of v. 7 ('the end of all things is near') makes the orientation-choice maximally significant.</p>",
    "3": "<p>'For you have spent enough time in the past doing what pagans choose to do — living in debauchery, lust, drunkenness, orgies, carousing, and detestable idolatry' — the catalogue of Gentile vices was a standard Jewish polemic against pagan lifestyle (cf. Wis 14:22-27; Gal 5:19-21; 1 Cor 6:9-10). Peter's specific list emphasizes the social-festive dimension of pagan religion: orgies (<em>komois</em>), carousings (<em>potois</em>), and idolatry (<em>athemitois eidōlolatriais</em>). The community's departure from these practices constitutes a social rupture — they no longer participate in the civic and family festivals that centered on sacrifice to the gods and the social drinking and feasting that surrounded them.</p>",
    "4": "<p>'They are surprised that you do not join them in their reckless, wild living, and they heap abuse on you' — the 'abuse' (<em>blasphēmountes</em>, blaspheming, slandering) that former associates heap on the converts expresses the social logic of the honor-shame world: departure from shared religious and social practice is experienced as a judgment against the group that continues it. The converts' refusal to participate is read not as neutral withdrawal but as implicit criticism. Roman-era sources confirm the hostility that greeted Jewish and Christian social non-conformity (Tacitus: 'hatred of the human race').</p>",
    "5": "<p>'But they will have to give account to him who is ready to judge the living and the dead' — the eschatological tribunal is the ultimate context for the community's suffering. The 'ready to judge' (<em>hetoimōs echonti krinai</em>) is the same eschatological urgency as v. 7 ('the end of all things is near'). The formula 'the living and the dead' becomes standard in early Christian creedal formulations (Acts 10:42; 2 Tim 4:1; the Apostles' Creed: 'he will come to judge the living and the dead'). The dual scope of the judgment means that those who have already died are not exempt from the accounting Peter describes.</p>",
    "6": "<p>'For this is the reason the gospel was preached even to those who are now dead, so that they might be judged according to human standards in regard to the body, but live according to God in regard to the spirit' — the 'dead' who were preached to are most naturally those who have died since their conversion — Christians who received the gospel, lived under social judgment ('judged according to human standards in the body'), and died. The gospel was preached to them so that though they experienced the mortal judgment of bodily death, they might live in the spirit according to God's standard. Peter assures a community that has lost members to death that those deaths are not the final word.</p>",
    "7": "<p>'The end of all things is near. Therefore be alert and of sober mind so that you may pray' — the eschatological urgency (<em>pantōn to telos ēngiken</em>) is the same verb Peter used in 1 Pet 4:5 and the same language as James 5:8 (the coming of the Lord has drawn near) and Rev 1:3 (the time is near). The sober-mindedness (<em>sōphronesate kai nēpsate</em>, be sensible and be sober) for prayer is not merely practical advice but eschatological preparation: the community alert to the nearness of the end will maintain the prayer-connection to the eschatological God.</p>",
    "8": "<p>'Above all, love each other deeply, because love covers over a multitude of sins' — the citation of Prov 10:12 ('love covers all offenses') is introduced with 'above all' (<em>pro pantōn</em>) — the highest priority among the community ethics. The 'covers' is not a euphemism for ignoring sins but the active covering that forgiveness provides: love creates the conditions for mutual forgiveness rather than mutual accusation. In a community under external social pressure, the internal environment of forgiving love is both a practical necessity and a theological embodiment of the gospel they proclaim.</p>",
    "9": "<p>'Offer hospitality to one another without grumbling' — the <em>philoxenia</em> (love of strangers/hospitality) commanded here was essential infrastructure for the early Christian movement: traveling missionaries, persecuted believers, and messengers relied on hospitality networks in the absence of safe commercial inns. The 'without grumbling' (<em>aneu gongysmou</em>) addresses the real burden of hosting: the <em>gongymos</em> was the complaint of the Israelites against Moses in the wilderness (Exod 16:7-12; Num 11:1; 14:27 LXX use <em>gongymos</em> for this grumbling). The hospitality that Peter mandates is cheerfully offered rather than grudgingly provided.</p>",
    "10": "<p>'Each of you should use whatever gift you have received to serve others, as faithful stewards of God's grace in its various forms' — the <em>charisma</em> (grace-gift) and <em>oikonomia</em> (stewardship) framework of Paul (1 Cor 12:4-11; Eph 4:11-13) appears here as the basis for community service. The 'various forms' (<em>poikilēs charitos theou</em>) of God's grace are the diversity of gifts that constitute the community's mutual service. The stewardship frame: the gifts are not the possessor's own but God's grace entrusted to them for others' benefit — a frame that prevents the spiritual arrogance that Paul also combats in 1 Corinthians.</p>",
    "11": "<p>'If anyone speaks, they should do so as one who speaks the very words of God. If anyone serves, they should do so with the strength God provides, so that in all things God may be praised through Jesus Christ' — the two categories (speaking and serving) encompass the full range of ministry. The speaker who 'speaks the very words of God' (<em>logia theou</em>) bears responsibility analogous to the OT prophet or the apostle — words that claim divine authority require absolute fidelity. The server who acts 'with the strength God provides' (<em>ex ischyos hēs chorēgei ho theos</em>) is the one who channels divine power rather than relying on human capacity alone. The goal: God's praise through Christ.</p>",
    "12": "<p>'Dear friends, do not be surprised at the fiery ordeal that has come on you to test you, as though something strange were happening to you' — the 'fiery ordeal' (<em>pyrōsei</em>) is the same root as the refiner's fire of Mal 3:2-3 and the furnace of Isa 48:10. Peter's primary purpose is pastoral re-framing: the community is tempted to interpret their suffering as divine abandonment or cosmic accident. The instruction 'do not be surprised' (<em>mē xenizesthe</em>) is the counterpart to v. 4's 'they are surprised' (<em>xenizontai</em>) that the community doesn't join in pagan living; the community's lack of surprise mirrors their former associates' surprise — but in the opposite direction.</p>",
    "13": "<p>'But rejoice inasmuch as you participate in the sufferings of Christ, so that you may be overjoyed when his glory is revealed' — the suffering-glory pattern (2:21-25; 3:18-22) returns as the eschatological frame for present experience. 'Participation in the sufferings of Christ' (<em>koinōneite tois tou Christou pathēmasin</em>) is the same koinonia-language that Paul uses in Phil 3:10 (to know Christ and the fellowship of his sufferings). The suffering is not incidental but structural: it participates in the Christ-pattern that defines the community's existence between the first and second coming.</p>",
    "14": "<p>'If you are insulted because of the name of Christ, you are blessed, for the Spirit of glory and of God rests on you' — the beatitude for suffering in the name of Christ echoes Matt 5:11 (blessed are you when people insult you and persecute you because of me). The 'name of Christ' (<em>en onomati Christou</em>) is the publicly confessed identification that makes the community a target: 'Christian' (<em>Christianos</em>) was a designation of public identification (Acts 11:26; 26:28), not just an internal self-description, and bearing it was what triggered the abuse of v. 4. The Spirit of glory that rests on them is the eschatological Spirit — the Spirit of the age to come already present in the suffering community.</p>",
    "15": "<p>'If you suffer, it should not be as a murderer or thief or any other kind of criminal, or even as a meddler' — the criminal categories enumerate the standard offenses prosecuted in Roman courts; 'meddler' (<em>allotrioepiskopos</em>, one who oversees others' affairs) is probably the charge of social interference — not keeping to one's own business, meddling in social arrangements. The point: Christian suffering must be specifically for being a Christian, not for genuine criminal conduct or for provocative social intervention. The legal context is the Roman judicial system, in which the community's good conduct should create a clear distinction between Christians and criminals.</p>",
    "16": "<p>'However, if you suffer as a Christian, do not be ashamed, but praise God that you bear that name' — the term 'Christian' (<em>Christianos</em>) appears only three times in the NT (Acts 11:26; 26:28; here). It was likely first used by outsiders as a political-social label (followers of Christos, a potentially seditious political figure in the Roman calculus). Peter takes the outsider label and invests it with honor: bearing the name is an occasion for praise, not shame. The reversal of shame into honor through the theological reframing of suffering is the pastoral heart of 1 Peter.</p>",
    "17": "<p>'For it is time for judgment to begin with God's household; and if it begins with us, what will the outcome be for those who do not obey the gospel of God?' — the sequence of judgment is drawn from Ezek 9:6 (begin at my sanctuary) — the divine judgment of Ezekiel's vision begins with the elders at the sanctuary before moving outward. The argument moves from 'we experience the purifying judgment of God's household' to 'if this is what the purifying judgment of the righteous looks like, what will the consuming judgment of the unrighteous look like?' The community's suffering is reinterpreted as the privileged beginning-point of eschatological judgment, not as being forsaken by God.</p>",
    "18": "<p>'If it is hard for the righteous to be saved, what will become of the ungodly and the sinner?' — the quotation is Prov 11:31 LXX. The 'hardness' of salvation for the righteous is not soteriological doubt but the observation that the path of faithful discipleship involves real cost, suffering, and refinement — the very suffering that Peter's communities are experiencing. If the path to salvation for those who are righteous is difficult (costly, requiring endurance), then the path for those who are ungodly is not merely difficult but catastrophic. The comparative makes the community's suffering a mark of privilege rather than a mark of divine disfavor.</p>",
    "19": "<p>'So then, those who suffer according to God's will should commit themselves to their faithful Creator and continue to do good' — the closing exhortation for the chapter synthesizes the whole argument: suffering-according-to-God's-will + self-commitment-to-the-faithful-Creator + continuing-good-works. The 'faithful Creator' (<em>pistō ktistē</em>) is a distinctive title: God as Creator who keeps faith with what he has made. The Creator's faithfulness grounds the entrusting of suffering — the God who made the world and sustains it can be trusted with the community's lives. The exhortation 'continue to do good' (<em>en agathopoiia</em>) returns to the public-witness strategy of 2:12 and 3:17 — visible goodness as both witness and protection."
  }
}

if __name__ == '__main__':
    existing = load_comm('mkt-context', '1peter')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-context', '1peter', existing)
    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / '1peter.json'))
    all_ok = True
    for ch in ['1', '2', '3', '4']:
        missing = set(il.get(ch, {}).keys()) - set(existing.get(ch, {}).keys())
        if missing:
            print(f'  ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch {ch}: complete ({len(existing.get(ch, {}))} verses)')
    if all_ok:
        print('All verses present')
